mapper.select:
SELECT *
FROM iot_notification_channel
WHERE tenant_id = #{tenantId}
  AND id = #{id}
  AND is_delete = 0
LIMIT 1

SELECT *
FROM iot_notification_channel
WHERE tenant_id = #{tenantId}
  AND is_delete = 0
ORDER BY id DESC
LIMIT #{pageSize} OFFSET #{offset}

mapper.update:
UPDATE iot_notification_channel
SET is_delete = 1, updated_at = CURRENT_TIMESTAMP
WHERE tenant_id = #{tenantId}
  AND id = #{id}
  AND is_delete = 0
